// ============================================================
// FIRMS CSV Processor – Madagascar
// Traitement unifié MODIS_NRT + VIIRS_NOAA20_NRT
// Équivalent JS du script Python Format_datetime + nettoyage
// ============================================================

const allItems = $input.all();
const processedRecords = [];
const processingErrors = [];

// ── 1. Parser CSV brut ───────────────────────────────────────
function parseCSV(csvText) {
  if (!csvText || typeof csvText !== 'string') return [];

  const lines = csvText
    .replace(/\r/g, '')  // normaliser CRLF
    .trim()
    .split('\n')
    .filter(l => l.trim() !== '');

  if (lines.length < 2) return [];

  // Headers en minuscules
  const headers = lines[0]
    .split(',')
    .map(h => h.trim().toLowerCase());

  const rows = [];
  for (let i = 1; i < lines.length; i++) {
    const vals = lines[i].split(',');
    if (vals.length < headers.length) continue;
    const row = {};
    headers.forEach((h, j) => {
      row[h] = (vals[j] !== undefined ? vals[j] : '').trim();
    });
    rows.push(row);
  }
  return rows;
}

// ── 2. Formatage datetime (equiv Python Format_datetime) ─────
// acq_time est HHMM sur 4 chiffres (ex: 538 → 0538)
function fmtAcqDatetime(acqDate, acqTime) {
  try {
    if (!acqDate) return null;
    const t = String(acqTime || '0').padStart(4, '0');
    const hh = t.slice(0, 2);
    const mm = t.slice(2, 4);
    if (parseInt(hh) > 23 || parseInt(mm) > 59) return null;
    const dt = new Date(`${acqDate}T${hh}:${mm}:00Z`);
    return isNaN(dt.getTime()) ? null : dt.toISOString();
  } catch (e) {
    return null;
  }
}

// ── 3. Validation et normalisation d'une ligne ───────────────
function processRow(row, source) {
  // Coordonnées
  const latitude  = parseFloat(row.latitude);
  const longitude = parseFloat(row.longitude);
  if (isNaN(latitude) || isNaN(longitude)) return null;

  // Bounds Madagascar (avec marge)
  if (latitude < -27 || latitude > -10.5 || longitude < 42 || longitude > 52) return null;

  // Datetime obligatoire
  const acq_datetime = fmtAcqDatetime(row.acq_date, row.acq_time);
  if (!acq_datetime) return null;

  // FRP valide et > 0 (condition métier : vrai feu détecté)
  const frp = parseFloat(row.frp);
  if (isNaN(frp) || frp <= 0) return null;

  // Résolution brightness selon capteur :
  // MODIS  → brightness   + bright_t31
  // VIIRS  → bright_ti4  + bright_ti5
  const raw_brightness = row.brightness || row.bright_ti4 || null;
  const raw_secondary  = row.bright_t31 || row.bright_ti5 || null;

  const brightness       = raw_brightness ? parseFloat(raw_brightness) : null;
  const bright_secondary = raw_secondary  ? parseFloat(raw_secondary)  : null;

  return {
    source,
    latitude,
    longitude,
    acq_datetime,
    satellite:       row.satellite   || null,
    instrument:      row.instrument  || null,
    confidence:      row.confidence !== undefined ? String(row.confidence) : null,
    version:         row.version     || null,
    frp,
    scan:            row.scan  ? parseFloat(row.scan)  : null,
    track:           row.track ? parseFloat(row.track) : null,
    daynight:        row.daynight ? row.daynight.toUpperCase().charAt(0) : null,
    brightness:      (brightness       !== null && !isNaN(brightness))       ? brightness       : null,
    bright_secondary:(bright_secondary !== null && !isNaN(bright_secondary)) ? bright_secondary : null
  };
}

// ── 4. Boucle principale ─────────────────────────────────────
for (const item of allItems) {
  const { source, data: csvData, fetchError } = item.json;

  // Erreur HTTP amont
  if (fetchError) {
    processingErrors.push(fetchError);
    continue;
  }

  if (!csvData || csvData.trim() === '') {
    processingErrors.push(`[${source}] Aucune donnée CSV reçue de l'API FIRMS`);
    continue;
  }

  // Vérifier que la réponse contient bien un header CSV attendu
  const lowerData = csvData.slice(0, 200).toLowerCase();
  if (!lowerData.includes('latitude') || (!lowerData.includes('brightness') && !lowerData.includes('bright_ti4'))) {
    processingErrors.push(`[${source}] Réponse API non-CSV : ${csvData.slice(0, 120)}`);
    continue;
  }

  try {
    const rows = parseCSV(csvData);
    let validCount = 0;

    for (const row of rows) {
      const record = processRow(row, source);
      if (record) {
        processedRecords.push(record);
        validCount++;
      }
    }

    if (validCount === 0) {
      processingErrors.push(`[${source}] 0 point valide sur ${rows.length} lignes CSV`);
    }
  } catch (e) {
    processingErrors.push(`[${source}] Erreur traitement CSV : ${e.message}`);
  }
}

// ── 5. Sortie ─────────────────────────────────────────────────
if (processedRecords.length === 0) {
  // Aucun point de feu → branche false du IF
  return [{
    json: {
      hasData: false,
      total_points: 0,
      errors: processingErrors,
      message: 'Aucun point de feu détecté pour Madagascar'
    }
  }];
}

// Points valides → branche true du IF
return processedRecords.map(record => ({
  json: {
    ...record,
    hasData: true
  }
}));

// ============================================================
// Nœud : "Générer SQL INSERT" – version corrigée
// Déduplication JS avant INSERT pour couvrir 100% des cas
// ============================================================

const records = $input.all().filter(item => item.json.hasData === true);

if (records.length === 0) {
  return [{ json: { hasData: false, query: null, count: 0 } }];
}

// ── 1. Clé composite UNIQUE (miroir exact de la contrainte DB) ──
//    source | latitude | longitude | acq_datetime | satellite
function dedupeKey(r) {
  return [
    r.source       || '',
    r.latitude,
    r.longitude,
    r.acq_datetime || '',
    r.satellite    || ''
  ].join('|');
}

// ── 2. Déduplication en mémoire ──────────────────────────────
//    Stratégie : on garde le record avec le FRP le plus élevé
//    en cas de collision (données plus récentes/précises)
const seen = new Map();
let dupCount = 0;

for (const item of records) {
  const r   = item.json;
  const key = dedupeKey(r);

  if (seen.has(key)) {
    dupCount++;
    const existing = seen.get(key);
    // Garder le FRP max (mesure la plus précise du feu)
    if ((r.frp || 0) > (existing.frp || 0)) {
      seen.set(key, r);
    }
  } else {
    seen.set(key, r);
  }
}

const dedupedRecords = [...seen.values()];

// ── 3. Echappement SQL robuste ────────────────────────────────
function sqlVal(val) {
  if (val === null || val === undefined) return 'NULL';
  if (typeof val === 'boolean')          return val ? 'TRUE' : 'FALSE';
  if (typeof val === 'number') {
    return (isNaN(val) || !isFinite(val)) ? 'NULL' : String(val);
  }
  if (typeof val === 'string') {
    return `'${val.replace(/'/g, "''")}'`;
  }
  return 'NULL';
}

// ── 4. Construire les VALUES ──────────────────────────────────
const valueRows = dedupedRecords.map(r => `  (${[
  sqlVal(r.source),
  sqlVal(r.latitude),
  sqlVal(r.longitude),
  sqlVal(r.acq_datetime),
  sqlVal(r.satellite),
  sqlVal(r.instrument),
  sqlVal(r.confidence),
  sqlVal(r.version),
  sqlVal(r.frp),
  sqlVal(r.scan),
  sqlVal(r.track),
  sqlVal(r.daynight),
  sqlVal(r.brightness),
  sqlVal(r.bright_secondary)
].join(', ')})`);

// ── 5. Requête finale avec ON CONFLICT complet ────────────────
//    La contrainte DB reste le filet de sécurité ultime
//    DO UPDATE uniquement si les valeurs ont réellement changé
const query = `INSERT INTO firms_fire_detections (
  source, latitude, longitude, acq_datetime,
  satellite, instrument, confidence, version,
  frp, scan, track, daynight,
  brightness, bright_secondary
) VALUES
${valueRows.join(',\n')}
ON CONFLICT (source, latitude, longitude, acq_datetime, satellite)
DO UPDATE SET
  frp              = GREATEST(EXCLUDED.frp, firms_fire_detections.frp),
  brightness       = EXCLUDED.brightness,
  bright_secondary = EXCLUDED.bright_secondary,
  confidence       = EXCLUDED.confidence,
  updated_at       = NOW()
WHERE
  firms_fire_detections.frp IS DISTINCT FROM EXCLUDED.frp
  OR firms_fire_detections.brightness IS DISTINCT FROM EXCLUDED.brightness;`;

return [{
  json: {
    query,
    hasData: true,
    count_raw:       records.length,
    count_deduped:   dedupedRecords.length,
    count_duplicates_removed: dupCount,
    sources: [...new Set(dedupedRecords.map(r => r.source))],
    inserted_at: new Date().toISOString()
  }
}];fa

// ============================================================
// Nœud : "Rapport d'Erreur DB" – FIRMS Madagascar
// Génère un rapport HTML stylisé en cas d'échec PostgreSQL
// À placer APRÈS le nœud PostgreSQL (branche onError ou suite)
// ============================================================

const item = $input.first();
const now  = new Date();

// ── 1. Extraction et classification de l'erreur ──────────────
function classifyError(raw) {
  const msg = (raw?.message || raw?.error?.message || JSON.stringify(raw) || '').toString();
  const code = raw?.code || raw?.error?.code || null;

  const types = [
    {
      id:      'CONN',
      label:   'Connexion impossible',
      pattern: /ECONNREFUSED|ENOTFOUND|connection refused|connect ETIMEDOUT/i,
      hint:    'Le serveur Supabase est inaccessible. Vérifier les credentials n8n et que le projet Supabase est actif.',
      severity:'critical'
    },
    {
      id:      'AUTH',
      label:   'Authentification refusée',
      pattern: /password authentication failed|role .* does not exist|SASL/i,
      hint:    'Mot de passe ou utilisateur incorrect dans les credentials n8n (Postgres).',
      severity:'critical'
    },
    {
      id:      'UNIQUE',
      label:   'Violation contrainte UNIQUE',
      pattern: /duplicate key value|unique constraint|23505/i,
      hint:    'La déduplication JS a laissé passer un doublon, ou la contrainte DB est plus stricte que prévu.',
      severity:'warning'
    },
    {
      id:      'SCHEMA',
      label:   'Erreur de schéma',
      pattern: /column .* does not exist|relation .* does not exist|syntax error|42703|42P01/i,
      hint:    'La table firms_fire_detections n\'existe pas ou une colonne a changé de nom. Relancer le SQL d\'initialisation.',
      severity:'critical'
    },
    {
      id:      'TIMEOUT',
      label:   'Timeout requête',
      pattern: /timeout|statement timeout|query_timeout/i,
      hint:    'Le batch INSERT est trop volumineux. Réduire la fenêtre d\'appel API ou fractionner le INSERT.',
      severity:'warning'
    },
    {
      id:      'SSL',
      label:   'Erreur SSL/TLS',
      pattern: /SSL|TLS|certificate|self signed/i,
      hint:    'Activer "SSL: require" dans les credentials n8n pour Supabase.',
      severity:'critical'
    },
    {
      id:      'DATA',
      label:   'Erreur de données',
      pattern: /invalid input syntax|value too long|out of range|22001|22003|22P02/i,
      hint:    'Une valeur mal formée a été envoyée. Vérifier le nœud "Process CSV → Records".',
      severity:'warning'
    },
  ];

  for (const t of types) {
    if (t.pattern.test(msg) || (code && t.pattern.test(String(code)))) {
      return { ...t, rawMessage: msg, code };
    }
  }

  return {
    id:       'UNKNOWN',
    label:    'Erreur inconnue',
    pattern:  null,
    hint:     'Consulter les logs n8n pour plus de détails.',
    severity: 'warning',
    rawMessage: msg,
    code
  };
}

// ── 2. Récupérer le contexte du batch depuis le nœud précédent ─
let batchContext = {};
try {
  // Le nœud "Générer SQL INSERT" expose ces champs
  const sqlNode = $('📝 Générer SQL INSERT').first().json;
  batchContext = {
    count_raw:               sqlNode.count_raw               ?? '—',
    count_deduped:           sqlNode.count_deduped           ?? '—',
    count_duplicates_removed: sqlNode.count_duplicates_removed ?? '—',
    sources:                 (sqlNode.sources || []).join(', ') || '—',
    inserted_at:             sqlNode.inserted_at             ?? '—'
  };
} catch (_) {
  batchContext = {
    count_raw: '—', count_deduped: '—',
    count_duplicates_removed: '—', sources: '—', inserted_at: '—'
  };
}

const error   = classifyError(item.json);
const execId  = $execution?.id  ?? 'N/A';
const wfName  = $workflow?.name ?? 'FIRMS Madagascar';

// ── 3. Helpers HTML ───────────────────────────────────────────
const fmt = d => new Date(d).toLocaleString('fr-FR', {
  timeZone: 'Indian/Antananarivo',
  day:'2-digit', month:'2-digit', year:'numeric',
  hour:'2-digit', minute:'2-digit', second:'2-digit'
});

const severityColor  = error.severity === 'critical' ? '#FF4545' : '#F5A623';
const severityLabel  = error.severity === 'critical' ? 'CRITIQUE' : 'AVERTISSEMENT';
const severityBg     = error.severity === 'critical'
  ? 'rgba(255,69,69,0.08)' : 'rgba(245,166,35,0.08)';
const severityBorder = error.severity === 'critical'
  ? 'rgba(255,69,69,0.35)' : 'rgba(245,166,35,0.35)';

// ── 4. Génération HTML ────────────────────────────────────────
const html = `<!DOCTYPE html>
