    font-size: 11px;
    color: var(--text-dim);
  }

  .exec-id {
    font-family: var(--mono);
    font-size: 11px;
    color: var(--text-muted);
    background: var(--bg-inset);
    border: 1px solid var(--border);
    padding: 3px 8px;
    border-radius: 3px;
  }
</style>
</head>
<body>
<div class="wrapper">

  <!-- Header -->
  <div class="header">
    <div>
      <div class="logo-row">
        <div class="logo-icon">
          <svg viewBox="0 0 18 18" fill="none" xmlns="http://www.w3.org/2000/svg">
            <path d="M9 2L11.5 7H16L12 10.5L13.5 16L9 13L4.5 16L6 10.5L2 7H6.5L9 2Z"
              fill="#0d0f12" stroke="#0d0f12" stroke-width="0.5"/>
          </svg>
        </div>
        <span class="header-title">FIRMS / Madagascar / n8n</span>
      </div>
      <div class="header-wf">Rapport d'erreur – Pipeline DB</div>
    </div>
    <div class="timestamp">
      <div>${fmt(now)}</div>
      <div style="margin-top:4px"><span class="exec-id">exec: ${execId}</span></div>
    </div>
  </div>

  <!-- Severity banner -->
  <div class="severity-banner">
    <div class="severity-dot"></div>
    <span class="severity-tag">${severityLabel}</span>
    <span class="severity-label">${error.label} [${error.id}]</span>
    ${error.code ? `<span class="severity-code">PG${error.code}</span>` : ''}
  </div>

  <!-- Card 1 : Message d'erreur brut -->
  <div class="card">
    <div class="card-header">
      <div class="card-header-dot"></div>
      <span class="card-title">Message d'erreur PostgreSQL</span>
    </div>
    <div class="error-msg-box">${
      error.rawMessage
        .replace(/&/g,'&amp;')
        .replace(/</g,'&lt;')
        .replace(/>/g,'&gt;')
    }</div>
    <div class="hint-box">
      <span class="hint-icon">HINT</span>
      <span class="hint-text">${error.hint}</span>
    </div>
  </div>

  <!-- Card 2 : Contexte du batch -->
  <div class="card">
    <div class="card-header">
      <div class="card-header-dot" style="background:#6366f1"></div>
      <span class="card-title">Contexte du batch FIRMS</span>
    </div>
    <div class="stats-row">
      <div class="stat-cell">
        <div class="stat-label">Points bruts</div>
        <div class="stat-value">${batchContext.count_raw}</div>
      </div>
      <div class="stat-cell">
        <div class="stat-label">Après dédup</div>
        <div class="stat-value">${batchContext.count_deduped}</div>
      </div>
      <div class="stat-cell">
        <div class="stat-label">Doublons retirés</div>
        <div class="stat-value warn">${batchContext.count_duplicates_removed}</div>
      </div>
    </div>
    <div class="kv-grid" style="padding:0">
      <div class="kv-row">
        <div class="kv-key">sources</div>
        <div class="kv-val">${batchContext.sources}</div>
      </div>
      <div class="kv-row">
        <div class="kv-key">horodatage batch</div>
        <div class="kv-val">${batchContext.inserted_at !== '—' ? fmt(batchContext.inserted_at) : '—'}</div>
      </div>
    </div>
  </div>

  <!-- Card 3 : Détails techniques -->
  <div class="card">
    <div class="card-header">
      <div class="card-header-dot" style="background:#f59e0b"></div>
      <span class="card-title">Détails techniques</span>
    </div>
    <div class="kv-grid">
      <div class="kv-row">
        <div class="kv-key">type</div>
        <div class="kv-val">${error.id}</div>
      </div>
      <div class="kv-row">
        <div class="kv-key">sévérité</div>
        <div class="kv-val" style="color:${severityColor}">${severityLabel}</div>
      </div>
      <div class="kv-row">
        <div class="kv-key">code PG</div>
        <div class="kv-val">${error.code ?? '—'}</div>
      </div>
      <div class="kv-row">
        <div class="kv-key">workflow</div>
        <div class="kv-val">${wfName}</div>
      </div>
      <div class="kv-row">
        <div class="kv-key">execution id</div>
        <div class="kv-val">${execId}</div>
      </div>
      <div class="kv-row">
        <div class="kv-key">nœud source</div>
        <div class="kv-val">🐘 PostgreSQL Supabase</div>
      </div>
      <div class="kv-row">
        <div class="kv-key">heure locale (EAT)</div>
        <div class="kv-val">${fmt(now)}</div>
      </div>
      <div class="kv-row">
        <div class="kv-key">heure UTC</div>
        <div class="kv-val">${now.toISOString()}</div>
      </div>
    </div>
  </div>

  <!-- Card 4 : Actions correctives -->
  <div class="card">
    <div class="card-header">
      <div class="card-header-dot" style="background:#22d3ee"></div>
      <span class="card-title">Actions correctives recommandées</span>
    </div>
    <div class="kv-grid">
      ${error.id === 'CONN' ? `
      <div class="kv-row">
        <div class="kv-key">01</div>
        <div class="kv-val">Vérifier que le projet Supabase est actif (dashboard.supabase.com)</div>
      </div>
      <div class="kv-row">
        <div class="kv-key">02</div>
        <div class="kv-val">Contrôler l'host/port dans les credentials n8n (db.&lt;ref&gt;.supabase.co:5432)</div>
      </div>
      <div class="kv-row">
        <div class="kv-key">03</div>
        <div class="kv-val">Vérifier que SSL est activé en mode "require"</div>
      </div>` : ''}
      ${error.id === 'AUTH' ? `
      <div class="kv-row">
        <div class="kv-key">01</div>
        <div class="kv-val">Régénérer le mot de passe DB dans Supabase → Settings → Database</div>
      </div>
      <div class="kv-row">
        <div class="kv-key">02</div>
        <div class="kv-val">Mettre à jour les credentials n8n avec le nouveau mot de passe</div>
      </div>` : ''}
      ${error.id === 'SCHEMA' ? `
      <div class="kv-row">
        <div class="kv-key">01</div>
        <div class="kv-val">Exécuter firms_supabase_init.sql dans l'éditeur SQL de Supabase</div>
      </div>
      <div class="kv-row">
        <div class="kv-key">02</div>
        <div class="kv-val">Vérifier que les colonnes du INSERT correspondent à la table actuelle</div>
      </div>` : ''}
      ${error.id === 'UNIQUE' ? `
      <div class="kv-row">
        <div class="kv-key">01</div>
        <div class="kv-val">Vérifier la clé de déduplication dans le nœud "Générer SQL INSERT"</div>
      </div>
      <div class="kv-row">
        <div class="kv-key">02</div>
        <div class="kv-val">Comparer la contrainte UNIQUE DB avec la Map JS (source+lat+lon+datetime+satellite)</div>
      </div>` : ''}
      ${error.id === 'TIMEOUT' ? `
      <div class="kv-row">
        <div class="kv-key">01</div>
        <div class="kv-val">Réduire la fenêtre d'appel API de 1 jour à 12 heures (/12 dans l'URL)</div>
      </div>
      <div class="kv-row">
        <div class="kv-key">02</div>
        <div class="kv-val">Fractionner le VALUES en plusieurs batches de 500 lignes max</div>
      </div>` : ''}
      ${(error.id === 'SSL' || error.id === 'DATA' || error.id === 'UNKNOWN') ? `
      <div class="kv-row">
        <div class="kv-key">01</div>
        <div class="kv-val">${error.hint}</div>
      </div>` : ''}
      <div class="kv-row">
        <div class="kv-key">réexécuter</div>
        <div class="kv-val">Corriger l'erreur puis relancer manuellement depuis n8n → Executions</div>
      </div>
    </div>
  </div>

  <!-- Footer -->
  <div class="footer">
    <span class="footer-left">FIRMS · MODIS + VIIRS · Madagascar</span>
    <span class="footer-right">NASA EARTHDATA · ${now.getFullYear()}</span>
  </div>

</div>
</body>
</html>`;

// ── 5. Sortie du nœud ─────────────────────────────────────────
return [{
  json: {
    status:         'db_error',
    error_type:     error.id,
    error_label:    error.label,
    severity:       error.severity,
    error_message:  error.rawMessage,
    pg_code:        error.code,
    hint:           error.hint,
    batch_context:  batchContext,
    workflow:       wfName,
    execution_id:   execId,
    timestamp:      now.toISOString(),
    html_report:    html
  }
}];

// ── Aucun point de feu détecté ──────────────────────────────
const item = $input.first();
console.log('[FIRMS] Exécution sans données :', JSON.stringify({
  timestamp: new Date().toISOString(),
  message: item.json.message,
  errors: item.json.errors
}));
return [{ json: { status: 'no_fire_detected', ...item.json } }];
